import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"چگونه کار می‌کند (How It Works)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/advanced/how-it-works.md","filePath":"fa/advanced/how-it-works.md"}'),i={name:"fa/advanced/how-it-works.md"};function l(n,e,s,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<div dir="rtl"><h1 id="چگونه-کار-می‌کند-how-it-works" tabindex="-1"><i class="ph ph-lightbulb"></i> چگونه کار می‌کند (How It Works) <a class="header-anchor" href="#چگونه-کار-می‌کند-how-it-works" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-lightbulb&quot;&gt;&lt;/i&gt; چگونه کار می‌کند (How It Works)&quot;">​</a></h1><p>راز کارایی WebAP در ماژولار بودن و رویکرد ریاضی آن نهفته است. این افزونه سعی نمی‌کند دلایل تأخیر را &quot;حدس&quot; بزند و کورکورانه وضوح صفحه را کاهش نمی‌دهد.</p><p>کل سیستم به‌عنوان یک خط لوله تنظیم‌شده (Pipeline) کار می‌کند که از سه لایه اصلی تشکیل شده است: <strong>Tracker</strong> (ردیاب)، <strong>Indexer</strong> (شاخص‌گذار) و <strong>Scalers</strong> (مقیاس‌کننده‌ها).</p><h2 id="خط-لوله-تصمیم‌گیری-decision-pipeline" tabindex="-1"><i class="ph ph-tree-view"></i> خط لوله تصمیم‌گیری (Decision Pipeline) <a class="header-anchor" href="#خط-لوله-تصمیم‌گیری-decision-pipeline" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-tree-view&quot;&gt;&lt;/i&gt; خط لوله تصمیم‌گیری (Decision Pipeline)&quot;">​</a></h2><p>معماری افزونه، جمع‌آوری داده‌ها، تصمیم‌گیری و اجرا را به‌شدت از هم جدا می‌کند.</p><h3 id="۱-tracker-ناظر" tabindex="-1">۱. Tracker (ناظر) <a class="header-anchor" href="#۱-tracker-ناظر" aria-label="Permalink to &quot;۱. Tracker (ناظر)&quot;">​</a></h3><p>هر فریم، Tracker داده‌های خام زمان فریم و زمان خالص CPU را جمع‌آوری می‌کند. این بخش میانگین متحرک نمایی (Exponential Moving Average) را برای هموارسازی جهش‌های تصادفی ناشی از Garbage Collector (GC) یا بارگذاری Assetها محاسبه می‌کند.<br> Tracker تصمیمی نمی‌گیرد، فقط به دو سؤال پاسخ می‌دهد:</p><ul><li><em>&quot;آیا از Target Min FPS پیروی می‌کنیم؟&quot;</em></li><li><em>&quot;در حال حاضر کدام زیرسیستم خاص (گلوگاه) باعث تأخیر می‌شود؟&quot;</em></li></ul><h3 id="۲-indexer-مغز" tabindex="-1">۲. Indexer (مغز) <a class="header-anchor" href="#۲-indexer-مغز" aria-label="Permalink to &quot;۲. Indexer (مغز)&quot;">​</a></h3><p>Indexer داده‌ها را از Tracker دریافت می‌کند و تصمیم می‌گیرد که چگونه ادامه دهد. این بخش به‌عنوان داور سیستم عمل می‌کند.<br> هنگام افت FPS، Indexer موارد زیر را انجام می‌دهد:<br> ۱. بررسی می‌کند که آیا سیستم در حالت <strong>Cooldown</strong> (زمان انتظار) است یا خیر.<br> ۲. <strong>سیستم جریمه ضد یویو</strong> را ارزیابی می‌کند (برای جزئیات بیشتر به بخش <a href="./anti-yoyo">جریمه ضد یویو</a> مراجعه کنید).<br> ۳. هزینه تمام Scalerهای موجود را محاسبه می‌کند.<br> ۴. به Scalerی فرمان می‌دهد که بیشترین عملکرد را با کمترین آسیب بصری ارائه دهد.</p><h3 id="۳-scalers-مجریان" tabindex="-1">۳. Scalers (مجریان) <a class="header-anchor" href="#۳-scalers-مجریان" aria-label="Permalink to &quot;۳. Scalers (مجریان)&quot;">​</a></h3><p>یک Scaler فرمانی را از Indexer دریافت کرده و کار سنگین را انجام می‌دهد. با API انجین Unity تعامل می‌کند و تنظیمات لازم (کاهش وضوح، پنهان کردن لایه‌ها، غیرفعال کردن Anti-Aliasing) را اعمال می‌کند.</p><h2 id="گلوگاه‌ها-bottlenecks-یافتن-مرز-بدون-دماسنج" tabindex="-1"><i class="ph ph-cpu"></i> گلوگاه‌ها (Bottlenecks): یافتن مرز بدون دماسنج <a class="header-anchor" href="#گلوگاه‌ها-bottlenecks-یافتن-مرز-بدون-دماسنج" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-cpu&quot;&gt;&lt;/i&gt; گلوگاه‌ها (Bottlenecks): یافتن مرز بدون دماسنج&quot;">​</a></h2><p>WebAP چگونه بدون دسترسی به سنسورهای دستگاه دقیقاً متوجه می‌شود که هنگام مدیریت بار چه چیزی دچار نقص است؟ این افزونه با تحلیل نسبت‌های زمان‌بندی (Timing Ratios) در خود انجین این کار را انجام می‌دهد.</p><ul><li><strong>گلوگاه پردازنده (CPU Bottleneck):</strong> Tracker زمان خالص روی نخ (Thread) اصلی پردازنده را بر کل زمان فریم تقسیم می‌کند. اگر این نسبت از <strong>۸۵٪</strong> بیشتر شود، نتیجه‌گیری واضح است: فریم توسط منطق یا محاسبات فیزیک محدود شده است. کاهش وضوح صفحه یا خاموش کردن سایه‌ها بی‌فایده خواهد بود.</li><li><strong>گلوگاه کارت گرافیک (GPU Bottleneck):</strong> اگر FPS کلی کمتر از حد نرمال باشد اما نسبت CPU زیر ۸۵٪ باشد، نشان‌دهنده بیکار بودن پردازنده است. این کارت گرافیک است که نمی‌تواند فریم را در زمان مقرر رندر کند (گلوگاه Fillrate، شیدرهای سنگین، یا Overdraw).</li><li><strong>نرخ فریم هدف (Target Frame Rate):</strong> اگر زمان انتظار VSync بیشتر از صفر باشد، به این معنی است که هم پردازنده و هم کارت گرافیک رندرینگ را سریع‌تر از نرخ تازه‌سازی (Refresh Rate) مانیتور به پایان رسانده‌اند. سیستم با حاشیه عملکرد (Performance Headroom) کار می‌کند و Indexer می‌تواند به‌آرامی کیفیت گرافیک را افزایش دهد.</li></ul><h2 id="zero-gc-عملکرد-در-اولویت" tabindex="-1"><i class="ph-fill ph-lightning"></i> Zero-GC: عملکرد در اولویت <a class="header-anchor" href="#zero-gc-عملکرد-در-اولویت" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-lightning&quot;&gt;&lt;/i&gt; Zero-GC: عملکرد در اولویت&quot;">​</a></h2><p>افزونه‌ای که برای نجات بازی شما از تأخیر طراحی شده است، هرگز نباید خودش باعث لگ شود. هسته WebAP با در نظر گرفتن صرفه‌جویی شدید در حافظه (Zero-GC) در طول مسیرهای پردازشی سنگین طراحی شده است.</p><ul><li><strong>بافرهای حلقوی O(1):</strong> به‌جای استفاده از لیست‌هایی مانند <code>List&lt;float&gt;</code> و حلقه‌های سنگین در <code>Update</code>، Tracker از آرایه‌های با اندازه ثابت (Ring Buffers) استفاده می‌کند. محاسبه میانگین FPS در زمان ثابت O(1) انجام می‌شود.</li><li><strong>بدون تخصیص (Allocation) در <code>Update</code>:</strong> هیچ‌گونه فراخوانی <code>new</code>، Boxing، یا Lambda در هسته وجود ندارد. Garbage Collector (GC) مطلقاً چیزی برای پاک کردن نخواهد داشت.</li><li><strong>کش نماینده‌ها (Delegate Cache):</strong> حتی برای کارهای پیچیده (نظیر رهگیری کلیک‌ها در <code>WebScaledPhysics2DRaycaster</code>)، ما از Reflection کُند (<code>MethodInfo.Invoke</code>) دوری کرده و از Delegateهای کامپایل‌شده سریع استفاده می‌کنیم.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title"><i class="ph-bold ph-note-pencil"></i> نامرئی بودن (Invisibility)</p><p>به لطف این بهینه‌سازی‌ها، هزینه پردازشی (Overhead) کل خط لوله WebAP به حداقل می‌رسد. پردازنده حتی متوجه نخواهد شد که در حال نظارت شدن است.</p></div></div>',1)])])}const u=t(i,[["render",l]]);export{g as __pageData,u as default};
